14	export function createEntity(world: World, ...traits: ConfigurableTrait[]): Entity {
15	    const ctx = world[$internal];
16	    const entity = allocateEntity(ctx.entityIndex);
17	
18	    for (const query of ctx.notQueries) {
19	        const match = query.check(world, entity);
20	        if (match) query.add(entity);
21	        // Reset all tracking bitmasks for the query.
22	        query.resetTrackingBitmasks(getEntityId(entity));
23	    }
24	
25	    ctx.entityTraits.set(entity, new Set());
26	    addTrait(world, entity, ...traits);
27	
28	    return entity;
